select
  c.id,
  f.id,
  s.id,
  a.ts,
  a.st,
  a.val
from _a a
-- cliente: match por id_externo
left join clientes c on c.id_externo = a.id_cli
-- funcionária: match por nome completo OU apelido
left join funcionarios f on (f.nome = a.colab or f.apelido = a.colab) and f.ativo = true
-- serviço: match exato primeiro, senão parcial
left join lateral (
  select id from servicos
  where nome = a.serv or nome ilike '%' || a.serv || '%'
  order by (nome = a.serv) desc
  limit 1
) s on true;

-- Confirmação
select count(*) as total_importado from agendamentos;